import{_ as i,o as n,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Sicherheit","description":"","frontmatter":{},"headers":[],"relativePath":"de/account/security.md","filePath":"de/account/security.md"}'),a={name:"de/account/security.md"};function o(s,e,l,h,u,c){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="sicherheit" tabindex="-1">Sicherheit <a class="header-anchor" href="#sicherheit" aria-label="Permalink to &quot;Sicherheit&quot;">​</a></h1><p>Schützen Sie Ihr Konto mit starker Authentifizierung und überwachen Sie den Zugang.</p><h2 id="passwort" tabindex="-1">Passwort <a class="header-anchor" href="#passwort" aria-label="Permalink to &quot;Passwort&quot;">​</a></h2><p>Verwenden Sie ein starkes, einzigartiges Passwort für Ihr MyCompanyDesk-Konto. Ändern Sie es unter <strong>Profil &gt; Passwort</strong>.</p><h3 id="passwortanforderungen" tabindex="-1">Passwortanforderungen <a class="header-anchor" href="#passwortanforderungen" aria-label="Permalink to &quot;Passwortanforderungen&quot;">​</a></h3><ul><li>Mindestens 8 Zeichen</li><li>Mischung aus Buchstaben, Zahlen und Sonderzeichen empfohlen</li></ul><h2 id="zwei-faktor-authentifizierung" tabindex="-1">Zwei-Faktor-Authentifizierung <a class="header-anchor" href="#zwei-faktor-authentifizierung" aria-label="Permalink to &quot;Zwei-Faktor-Authentifizierung&quot;">​</a></h2><p>Fügen Sie Ihrem Konto eine zusätzliche Sicherheitsebene hinzu:</p><ol><li>Gehen Sie zu <strong>Profil &gt; Sicherheit</strong></li><li>Klicken Sie auf <strong>Zwei-Faktor-Authentifizierung aktivieren</strong></li><li>Scannen Sie den QR-Code mit Ihrer Authenticator-App (Google Authenticator, Authy usw.)</li><li>Geben Sie den Bestätigungscode ein, um zu bestätigen</li><li>Speichern Sie Ihre <strong>Wiederherstellungscodes</strong> an einem sicheren Ort</li></ol><p>Mit aktivierter 2FA benötigen Sie sowohl Ihr Passwort als auch einen Code aus Ihrer Authenticator-App, um sich anzumelden.</p><h3 id="_2fa-deaktivieren" tabindex="-1">2FA deaktivieren <a class="header-anchor" href="#_2fa-deaktivieren" aria-label="Permalink to &quot;2FA deaktivieren&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Profil &gt; Sicherheit</strong></li><li>Klicken Sie auf <strong>Zwei-Faktor-Authentifizierung deaktivieren</strong></li><li>Geben Sie Ihr Passwort zur Bestätigung ein</li></ol><h2 id="sitzungsverwaltung" tabindex="-1">Sitzungsverwaltung <a class="header-anchor" href="#sitzungsverwaltung" aria-label="Permalink to &quot;Sitzungsverwaltung&quot;">​</a></h2><p>Sehen und verwalten Sie Ihre aktiven Sitzungen:</p><ul><li>Alle Geräte und Browser anzeigen, bei denen Sie angemeldet sind</li><li>Letzte Aktivitätszeit für jede Sitzung einsehen</li><li>Nicht erkannte Sitzungen <strong>widerrufen</strong></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Wenn Sie eine Sitzung sehen, die Sie nicht erkennen, widerrufen Sie sie sofort und ändern Sie Ihr Passwort.</p></div><h2 id="social-login" tabindex="-1">Social Login <a class="header-anchor" href="#social-login" aria-label="Permalink to &quot;Social Login&quot;">​</a></h2><p>Wenn Sie Google oder Microsoft zur Anmeldung verwenden:</p><ul><li>Ihre Authentifizierung wird vom Anbieter gehandhabt</li><li>MyCompanyDesk sieht oder speichert Ihr Google-/Microsoft-Passwort nie</li><li>Sie können Social Login über <strong>Profil &gt; Verbundene Apps</strong> trennen</li></ul><h2 id="datenschutz" tabindex="-1">Datenschutz <a class="header-anchor" href="#datenschutz" aria-label="Permalink to &quot;Datenschutz&quot;">​</a></h2><p>MyCompanyDesk nimmt Datensicherheit ernst:</p><ul><li>Alle Daten werden über HTTPS übertragen</li><li>Passwörter werden mit bcrypt gehasht</li><li>Datenbankverbindungen sind verschlüsselt</li><li>Regelmäßige Backups gewährleisten Datensicherheit</li><li>DSGVO-konforme Datenverarbeitung</li></ul><h2 id="kontoloschung" tabindex="-1">Kontolöschung <a class="header-anchor" href="#kontoloschung" aria-label="Permalink to &quot;Kontolöschung&quot;">​</a></h2><p>Wenn Sie Ihr Konto löschen müssen:</p><ol><li>Gehen Sie zu <strong>Profil &gt; Daten</strong></li><li>Klicken Sie auf <strong>Konto löschen</strong></li><li>Geben Sie Ihr Passwort zur Bestätigung ein</li><li>Alle Ihre Daten werden dauerhaft entfernt</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Die Kontolöschung ist unwiderruflich. Exportieren Sie Ihre Daten vorher, wenn Sie eine Sicherungskopie benötigen.</p></div>',26)])])}const S=i(a,[["render",o]]);export{g as __pageData,S as default};
